async function fetchAmoCrmDepartmentTaskCounts(){
  if (typeof ENABLE_AMOCRM !== 'undefined' && !ENABLE_AMOCRM) {
    return { data: [], error: null };
  }
  return sb
    .from('amocrm_department_task_counts')
    .select(`
      responsible_user_id,
      department_name,
      sort_order,
      active_tasks,
      overdue_tasks,
      on_time_tasks,
      nearest_deadline
    `)
    .order('sort_order', { ascending: true });
}
function formatHm(totalSeconds){
  if(!totalSeconds)return '—';
  const h=Math.floor(totalSeconds/3600);
  const m=Math.floor((totalSeconds%3600)/60);
  return `${h} ${t('soat')} ${m} ${t('daqiqa')}`;
}
function trFeedbackType(type){
  if(type==='complaint')return t('feedback_type_complaint');
  if(type==='suggestion')return t('feedback_type_suggestion');
  return t('feedback_type_other');
}
function trEmpState(state){
  const map={not_started:t('st0'),working:t('st1'),lunch:t('st2'),prayer:t('prayer_btn'),paused:t('paused'),ended:t('st4')};
  return map[state] || '';
}
function emptyText(key, padded=false){
  return `<p style="color:var(--text3);font-size:12px;${padded?'padding:10px':''}">${t(key)}</p>`;
}
function normalizeDynamicTranslations(root=document){
  if(!root)return;
  root.querySelectorAll('.fb-type.complaint').forEach(el=>el.textContent=t('feedback_type_complaint'));
  root.querySelectorAll('.fb-type.suggestion').forEach(el=>el.textContent=t('feedback_type_suggestion'));
  root.querySelectorAll('.fb-type.other').forEach(el=>el.textContent=t('feedback_type_other'));
  root.querySelectorAll('.fb-replied').forEach(el=>{
    el.textContent = el.textContent
      .replace(/^.*Admin:\s*/i, `${t('feedback_admin_reply')} `)
      .replace(/^.*Javobingiz:\s*/i, `${t('feedback_your_reply')} `);
  });
  root.querySelectorAll('textarea[id^="reply_"]').forEach(el=>el.placeholder=t('feedback_reply_placeholder'));
  root.querySelectorAll('.fb-reply-area .bb').forEach(el=>el.textContent=t('feedback_reply_send'));
  root.querySelectorAll('.dash-empty').forEach(el=>el.textContent=t('loading'));
  root.querySelectorAll('.badge.bauto').forEach(el=>{
    if(/auto/i.test(el.textContent))el.textContent=`⚙️ ${t('auto_label')}`;
  });
}

