function rerenderLocalizedViews(){
  const adminPage = document.getElementById('adminPage');
  const employeePage = document.getElementById('employeePage');
  const adminVisible = adminPage && getComputedStyle(adminPage).display !== 'none';
  const employeeVisible = employeePage && getComputedStyle(employeePage).display !== 'none';

  if(adminVisible){
    loadAtt();
    loadDashboard();
    loadMonthly();
    loadTodayWorkLeaveCard();
    const feedbackTab=document.getElementById('tab_feedback');
    const notifTab=document.getElementById('tab_notif');
    const settingsTab=document.getElementById('tab_settings');
    const amoCrmTab=document.getElementById('tab_amocrm');
    if(feedbackTab && !feedbackTab.classList.contains('hidden'))loadFeedbackAdmin();
    if(notifTab && !notifTab.classList.contains('hidden'))loadNotificationsAdmin();
    if(settingsTab && !settingsTab.classList.contains('hidden'))loadEmpList();
    if(amoCrmTab && !amoCrmTab.classList.contains('hidden')){
      renderAmoCrmTaskPage();
    }
  }

  if(employeeVisible && CU){
    loadHist();
    const notifTab=document.getElementById('emp_tab_notif');
    const feedbackTab=document.getElementById('emp_tab_feedback');
    if(notifTab && !notifTab.classList.contains('hidden'))loadNotificationsEmp(false);
    if(feedbackTab && !feedbackTab.classList.contains('hidden'))loadMyFeedback();
  }
}

